parameters.jsCode:
const raw = $input.first().json.text ||
            $input.first().json.output ||
            $input.first().json.content || '';

const formData = $('Extract & Map Form Fields').first().json;

let aiParsed;
try {
  const cleaned = raw.replace(/```json|```/g, '').replace(/\n/g, ' ').trim();
  aiParsed = JSON.parse(cleaned);
} catch(e) {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    try { aiParsed = JSON.parse(match[0]); }
    catch(e2) { throw new Error(`AI parse failed: ${raw.substring(0,200)}`); }
  } else {
    throw new Error(`No JSON in AI output: ${raw.substring(0,200)}`);
  }
}

return (aiParsed.moves || []).map(move => ({
  json: {
    ...formData,
    moveId:         move.moveId,
    moveName:       move.moveName,
    moveIcon:       move.moveIcon || '🎬',
    moveStyle:      move.moveStyle,
    supervisorNote: move.supervisorNote,
    shotIntent:     aiParsed.shotIntent,
    safePrompt:     JSON.stringify(
      `${move.seedancePrompt}. Shot: ${formData.shotCode}. ${formData.lensSpecs}. --duration 5 --camerafixed false`
    ).slice(1,-1),
    totalMoves:     (aiParsed.moves || []).length
  }
}));

const input = $input.first().json;

const body = {
  model: 'seedance-1-5-pro-251215',
  content: [
    { type: 'text', text: input.safePrompt },
    { type: 'image_url', image_url: { url: input.plateImageUrl } }
  ],
  generate_audio: false,
  ratio: '16:9',
  duration: 5,
  watermark: false
};

return [{ json: { ...input, requestBody: JSON.stringify(body) } }];

const httpResult = $input.first().json;
const moveData = $('Build Seedance API Request').first().json;
return [{ json: { ...moveData, id: httpResult.id } }];

const pollResult = $input.first().json;
const moveData   = $('Store Job ID + Move Metadata').first().json;

let videoUrl = null;
if (pollResult.content && pollResult.content.video_url) {
  videoUrl = pollResult.content.video_url;
}
if (!videoUrl) videoUrl = `Not found. Job: ${pollResult.id}`;

const keyFrames = [
  { frame: 1,   timecode: '00:00:00:01', label: 'Opening frame — camera start position' },
  { frame: 48,  timecode: '00:00:02:00', label: 'Peak move — maximum camera energy' },
  { frame: 120, timecode: '00:00:05:00', label: 'Landing frame — final composition' }
];

return [{ json: {
  moveId:          moveData.moveId,
  moveName:        moveData.moveName,
  moveIcon:        moveData.moveIcon,
  moveStyle:       moveData.moveStyle,
  supervisorNote:  moveData.supervisorNote,
  shotIntent:      moveData.shotIntent,
  shotCode:        moveData.shotCode,
  sequenceCode:    moveData.sequenceCode,
  complexity:      moveData.complexity,
  lensSpecs:       moveData.lensSpecs,
  scriptSnippet:   moveData.scriptSnippet,
  supervisorEmail: moveData.supervisorEmail,
  plateImageUrl:   moveData.plateImageUrl,
  videoUrl,
  jobId:           pollResult.id,
  resolution:      pollResult.resolution,
  duration:        pollResult.duration,
  keyFrames,
  totalMoves:      moveData.totalMoves,
  generatedAt:     new Date().toISOString()
}}];

