const allMoves = $input.all().map(i => i.json);
const first = allMoves[0];

const moveCards = allMoves.map((m, idx) => {
  const letter = String.fromCharCode(65 + idx);
  return `${m.moveIcon} *Option ${letter} — ${m.moveName}* (${m.moveId})\n` +
    `> 🎥 Style: ${m.moveStyle}\n` +
    `> 💡 ${m.supervisorNote}\n` +
    `> 🎬 <${m.videoUrl}|Watch Option ${letter}>\n` +
    `> 📍 Key Frames: ${m.keyFrames.map(k => k.label).join(' → ')}`;
}).join('\n\n');

const jiraDesc = allMoves.map((m, idx) => {
  const letter = String.fromCharCode(65 + idx);
  return `*Option ${letter}: ${m.moveName}*\n${m.supervisorNote}\nVideo: ${m.videoUrl}`;
}).join('\n\n');

const tableRows = allMoves.map((m, idx) => {
  const letter = String.fromCharCode(65 + idx);
  return `<tr>
    <td><strong>Option ${letter}</strong></td>
    <td>${m.moveIcon} ${m.moveName}</td>
    <td>${m.moveStyle}</td>
    <td>${m.supervisorNote}</td>
    <td><a href="${m.videoUrl}">Watch</a></td>
    <td>${m.resolution || '720p'}</td>
  </tr>`;
}).join('');

const lookbookHtml = `<h1>🎬 AI Previs Board — ${first.shotCode}</h1>
<p><strong>Sequence:</strong> ${first.sequenceCode} | <strong>Shot Intent:</strong> ${first.shotIntent}</p>
<p><strong>Script:</strong> ${first.scriptSnippet}</p>
<p><strong>Lens/Camera:</strong> ${first.lensSpecs} | <strong>Complexity:</strong> ${first.complexity}</p>
<h2>Camera Options — Supervisor: Please select one</h2>
<table><thead><tr><th>Option</th><th>Name</th><th>Style</th><th>Director Note</th><th>Video</th><th>Res</th></tr></thead><tbody>${tableRows}</tbody></table>
<h2>Key Frame Guide</h2>
<ul>${first.keyFrames.map(k => `<li><strong>${k.timecode}</strong> — ${k.label}</li>`).join('')}</ul>
<p><em>Generated by AI Previs Pipeline — ${new Date().toISOString()}</em></p>`;

return [{ json: {
  shotCode:        first.shotCode,
  sequenceCode:    first.sequenceCode,
  shotIntent:      first.shotIntent,
  scriptSnippet:   first.scriptSnippet,
  lensSpecs:       first.lensSpecs,
  complexity:      first.complexity,
  supervisorEmail: first.supervisorEmail,
  plateImageUrl:   first.plateImageUrl,
  allMoves,
  moveCards,
  jiraDesc,
  lookbookHtml,
  totalMoves:      allMoves.length,
  generatedAt:     new Date().toISOString()
}}];

